contracts/core/Config.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title Config
 * @notice 参数配置管理合约 - 所有可调参数唯一存储
 * @dev 所有修改必须通过 Timelock，并 emit 新旧值
 */
contract Config is AccessControl, Pausable {
    // ==================== 角色定义 ====================
    bytes32 public constant DAO_ROLE = keccak256("DAO_ROLE");
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant GUARDIAN_ROLE = keccak256("GUARDIAN_ROLE");

    // ==================== 时间常量 ====================
    uint256 public rfqValidityPeriod = 2 hours;              // RFQ有效期
    uint256 public quoteValidityPeriod = 30 minutes;         // 报价有效期
    uint256 public initialFeedDeadline = 10 minutes;         // 初始喂价时限
    uint256 public closingFeedDeadline = 10 minutes;         // 平仓喂价时限
    uint256 public defaultMarginCallDeadline = 12 hours;     // 默认追保截止时间
    uint256 public cryptoMarginCallDeadline = 2 hours;       // 加密货币追保截止时间
    uint256 public settlementArbitrationWindow = 24 hours;   // 平仓结算仲裁窗口
    uint256 public defaultArbitrationWindow = 12 hours;      // 其他场景仲裁窗口

    // ==================== 费率常量 (基点 1 = 0.01%) ====================
    uint256 public creationFee = 1 ether;                    // 建仓手续费：1U
    uint256 public tradingFeeRate = 10;                      // 交易手续费：0.1%
    uint256 public arbitrationFee = 30 ether;                // 仲裁费：30U
    uint256 public nstDiscount = 80;                         // NST折扣：80%

    // ==================== 喂价费用 ====================
    uint256 public feedFee_5_3 = 3 ether;                    // 5-3档：3U
    uint256 public feedFee_7_5 = 5 ether;                    // 7-5档：5U
    uint256 public feedFee_10_7 = 8 ether;                   // 10-7档：8U
    uint256 public feedPlatformShare = 10;                   // 平台抽成：10%
    uint256 public feedFeederShare = 90;                     // 喂价员分配：90%

    // ==================== 保证金参数 ====================
    uint256 public minMarginRate = 1000;                     // 最低保证金率：10%（自由卖方）
    uint256 public seatSellerInitialMargin = 0;              // 席位卖方初始保证金：0

    // ==================== 喂价员参数 ====================
    uint256 public minFeederStake = 100 ether;               // 喂价员最低质押：100U

    // ==================== 限制参数 ====================
    uint256 public maxQuotesPerBuyerOrder = 5;               // 买方单最大报价数
    uint256 public maxQuotesPerSellerOrder = 1;              // 卖方单报价即成交
    uint256 public maxConsecutiveDays = 10;                  // 最大连续天数
    uint256 public defaultDailyLimitPercent = 30;            // 默认单日涨幅阈值
    uint256 public minExerciseDelay = 1;                     // 最小行权延迟T+1
    uint256 public maxExerciseDelay = 5;                     // 最大行权延迟T+5

    // ==================== 积分参数 ====================
    uint256 public pointsMultiplier = 100;                   // 积分倍率：1U = 100分

    // ==================== 违约金参数 ====================
    uint256 public initialFeedPenaltyRate = 500;             // 初始喂价超时违约金：5% (基点)
    uint256 public closingFeedPenaltyRate = 500;             // 平仓喂价超时违约金：5% (基点)

    // ==================== 资金池分配比例 (基点 100 = 1%) ====================
    uint256 public nodeRewardShare = 500;                    // 节点奖励：5%
    uint256 public tokenBuybackShare = 1000;                 // 代币回购：10%
    uint256 public lpPoolShare = 1000;                       // LP池：10%
    uint256 public teamFundShare = 3000;                     // 团队：30%
    uint256 public foundationShare = 2500;                   // 基金会：25%
    uint256 public daoShare = 1000;                          // DAO：10%
    uint256 public growthNodeShare = 1000;                   // 成长节点：10%

    // ==================== NST 代币折扣 (P1) ====================
    uint256 public nstDiscountRate = 8000;                   // NST支付折扣：80% (8000基点 = 80%)
    bool public nstDiscountEnabled = true;                   // 启用NST折扣


    // ==================== 合约地址 ====================
    address public usdtAddress;
    address public usdcAddress;
    address public nstTokenAddress;
    address public vaultManagerAddress;
    address public optionsCoreAddress;
    address public feedProtocolAddress;
    address public seatManagerAddress;
    address public pointsManagerAddress;

    // ==================== 事件 ====================
    event ParameterUpdated(
        string indexed paramName,
        uint256 oldValue,
        uint256 newValue,
        uint256 timestamp
    );

    event AddressUpdated(
        string indexed paramName,
        address oldAddress,
        address newAddress,
        uint256 timestamp
    );

    // ==================== 构造函数 ====================
    constructor(address _admin) {
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(DAO_ROLE, _admin);
        _grantRole(OPERATOR_ROLE, _admin);
        _grantRole(GUARDIAN_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier onlyDAO() {
        require(hasRole(DAO_ROLE, msg.sender), "Config: caller is not DAO");
        _;
    }

    modifier onlyOperator() {
        require(hasRole(OPERATOR_ROLE, msg.sender), "Config: caller is not Operator");
        _;
    }

    modifier onlyGuardian() {
        require(hasRole(GUARDIAN_ROLE, msg.sender), "Config: caller is not Guardian");
        _;
    }

    // ==================== 暂停功能 ====================
    function pause() external onlyGuardian {
        _pause();
    }

    function unpause() external onlyDAO {
        _unpause();
    }

    // ==================== 参数设置函数 ====================
    
    /**
     * @notice 设置 RFQ 有效期
     */
    function setRfqValidityPeriod(uint256 _value) external onlyDAO {
        uint256 oldValue = rfqValidityPeriod;
        rfqValidityPeriod = _value;
        emit ParameterUpdated("rfqValidityPeriod", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置报价有效期
     */
    function setQuoteValidityPeriod(uint256 _value) external onlyDAO {
        uint256 oldValue = quoteValidityPeriod;
        quoteValidityPeriod = _value;
        emit ParameterUpdated("quoteValidityPeriod", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置建仓手续费
     */
    function setCreationFee(uint256 _value) external onlyDAO {
        uint256 oldValue = creationFee;
        creationFee = _value;
        emit ParameterUpdated("creationFee", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置交易手续费率
     */
    function setTradingFeeRate(uint256 _value) external onlyDAO {
        uint256 oldValue = tradingFeeRate;
        tradingFeeRate = _value;
        emit ParameterUpdated("tradingFeeRate", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置仲裁费
     */
    function setArbitrationFee(uint256 _value) external onlyDAO {
        uint256 oldValue = arbitrationFee;
        arbitrationFee = _value;
        emit ParameterUpdated("arbitrationFee", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置最低保证金率
     */
    function setMinMarginRate(uint256 _value) external onlyDAO {
        uint256 oldValue = minMarginRate;
        minMarginRate = _value;
        emit ParameterUpdated("minMarginRate", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置喂价员最低质押
     */
    function setMinFeederStake(uint256 _value) external onlyDAO {
        uint256 oldValue = minFeederStake;
        minFeederStake = _value;
        emit ParameterUpdated("minFeederStake", oldValue, _value, block.timestamp);
    }

    // ==================== 地址设置函数 ====================

    /**
     * @notice 设置 USDT 地址
     */
    function setUsdtAddress(address _address) external onlyDAO {
        address oldAddress = usdtAddress;
        usdtAddress = _address;
        emit AddressUpdated("usdtAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 VaultManager 地址
     */
    function setVaultManagerAddress(address _address) external onlyDAO {
        address oldAddress = vaultManagerAddress;
        vaultManagerAddress = _address;
        emit AddressUpdated("vaultManagerAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 OptionsCore 地址
     */
    function setOptionsCoreAddress(address _address) external onlyDAO {
        address oldAddress = optionsCoreAddress;
        optionsCoreAddress = _address;
        emit AddressUpdated("optionsCoreAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 FeedProtocol 地址
     */
    function setFeedProtocolAddress(address _address) external onlyDAO {
        address oldAddress = feedProtocolAddress;
        feedProtocolAddress = _address;
        emit AddressUpdated("feedProtocolAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 SeatManager 地址
     */
    function setSeatManagerAddress(address _address) external onlyDAO {
        address oldAddress = seatManagerAddress;
        seatManagerAddress = _address;
        emit AddressUpdated("seatManagerAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 PointsManager 地址
     */
    function setPointsManagerAddress(address _address) external onlyDAO {
        address oldAddress = pointsManagerAddress;
        pointsManagerAddress = _address;
        emit AddressUpdated("pointsManagerAddress", oldAddress, _address, block.timestamp);
    }

    // ==================== 查询函数 ====================

    /**
     * @notice 获取喂价费用
     * @param tier 喂价档位 (0=5-3, 1=7-5, 2=10-7)
     */
    function getFeedFee(uint8 tier) external view returns (uint256) {
        if (tier == 0) return feedFee_5_3;
        if (tier == 1) return feedFee_7_5;
        if (tier == 2) return feedFee_10_7;
        revert("Config: invalid feed tier");
    }

    /**
     * @notice 获取追保截止时间
     * @param isCrypto 是否为加密货币/外汇
     */
    function getMarginCallDeadline(bool isCrypto) external view returns (uint256) {
        return isCrypto ? cryptoMarginCallDeadline : defaultMarginCallDeadline;
    }

    /**
     * @notice 获取仲裁窗口
     * @param isSettlement 是否为平仓结算
     */
    function getArbitrationWindow(bool isSettlement) external view returns (uint256) {
        return isSettlement ? settlementArbitrationWindow : defaultArbitrationWindow;
    }

    // ==================== NST 折扣函数 (P1) ====================

    /**
     * @notice 计算 NST 折扣后的费用
     * @param originalFee 原始费用
     * @return 折扣后的费用（使用 NST 支付时为 80%）
     */
    function getDiscountedFee(uint256 originalFee) external view returns (uint256) {
        if (!nstDiscountEnabled) {
            return originalFee;
        }
        // nstDiscountRate = 8000 表示 80%
        return (originalFee * nstDiscountRate) / 10000;
    }

    /**
     * @notice 设置 NST 折扣率
     * @param _rate 折扣率（基点，8000 = 80%）
     */
    function setNstDiscountRate(uint256 _rate) external onlyDAO {
        require(_rate > 0 && _rate <= 10000, "Config: invalid discount rate");
        uint256 oldValue = nstDiscountRate;
        nstDiscountRate = _rate;
        emit ParameterUpdated("nstDiscountRate", oldValue, _rate, block.timestamp);
    }

    /**
     * @notice 启用/禁用 NST 折扣
     */
    function setNstDiscountEnabled(bool _enabled) external onlyDAO {
        nstDiscountEnabled = _enabled;
    }
}

contracts/core/OptionsCore.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../libraries/NSTTypes.sol";
import "../interfaces/IOptionsCore.sol";
import "../vault/VaultManager.sol";
import "./Config.sol";

/**
 * @title OptionsCore
 * @notice 期权核心合约 - 订单创建、撮合、喂价
 * @dev 结算/保证金/仲裁功能已拆分到 OptionsSettlement 合约
 */
contract OptionsCore is IOptionsCore, AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 角色定义 ====================
    bytes32 public constant FEED_PROTOCOL_ROLE = keccak256("FEED_PROTOCOL_ROLE");
    bytes32 public constant SETTLEMENT_ROLE = keccak256("SETTLEMENT_ROLE");

    // ==================== 状态变量 ====================
    Config public config;
    VaultManager public vaultManager;
    IERC20 public usdt;

    uint256 public nextOrderId = 1;
    uint256 public nextQuoteId = 1;

    // 订单存储
    mapping(uint256 => Order) public orders;
    mapping(uint256 => Quote[]) public orderQuotes;
    mapping(uint256 => Quote) public quotes;

    // 用户订单索引
    mapping(address => uint256[]) public buyerOrders;
    mapping(address => uint256[]) public sellerOrders;

    // 订单检索索引
    mapping(string => uint256[]) private ordersByCountry;
    mapping(string => uint256[]) private ordersByMarket;
    mapping(string => uint256[]) private ordersByCode;

    // ==================== 构造函数 ====================
    constructor(
        address _config,
        address _vaultManager,
        address _usdt,
        address _admin
    ) {
        config = Config(_config);
        vaultManager = VaultManager(_vaultManager);
        usdt = IERC20(_usdt);
        
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier validOrder(uint256 orderId) {
        require(orderId > 0 && orderId < nextOrderId, "OptionsCore: invalid order id");
        _;
    }

    modifier onlyBuyer(uint256 orderId) {
        require(msg.sender == orders[orderId].buyer, "OptionsCore: not buyer");
        _;
    }

    modifier onlySeller(uint256 orderId) {
        require(msg.sender == orders[orderId].seller, "OptionsCore: not seller");
        _;
    }

    modifier inStatus(uint256 orderId, OrderStatus status) {
        require(orders[orderId].status == status, "OptionsCore: invalid status");
        _;
    }

    // ==================== 买方功能 ====================

    /**
     * @notice 买方创建询价订单
     */
    function createBuyerRFQ(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 maxPremiumRate,
        uint256 minMarginRate,
        SellerType acceptedSellerType,
        address designatedSeller,
        uint256 arbitrationWindow,
        uint256 marginCallDeadline,
        bool dividendAdjustment,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent,
        FeedRule feedRule
    ) external override nonReentrant whenNotPaused returns (uint256 orderId) {
        require(notionalUSDT > 0, "OptionsCore: notional must be positive");
        require(expiryTimestamp > block.timestamp, "OptionsCore: expiry must be in future");

        // 收取建仓手续费 1U（通过 VaultManager 正式入账到利润池）
        vaultManager.collectFee(msg.sender, address(usdt), config.creationFee(), "creation_fee");

        orderId = nextOrderId++;
        Order storage order = orders[orderId];
        order.orderId = orderId;
        order.buyer = msg.sender;
        order.underlyingName = underlyingName;
        order.underlyingCode = underlyingCode;
        order.market = market;
        order.country = country;
        order.refPrice = refPrice;
        order.direction = direction;
        order.notionalUSDT = notionalUSDT;
        order.expiryTimestamp = expiryTimestamp;
        order.maxPremiumRate = maxPremiumRate;
        order.minMarginRate = minMarginRate;
        order.sellerType = acceptedSellerType;
        order.designatedSeller = designatedSeller;
        order.arbitrationWindow = arbitrationWindow;
        order.marginCallDeadline = marginCallDeadline;
        order.dividendAdjustment = dividendAdjustment;
        order.exerciseDelay = 0;
        // 新增：平仓规则和喂价规则
        order.liquidationRule = liquidationRule;
        order.consecutiveDays = consecutiveDays;
        order.dailyLimitPercent = dailyLimitPercent;
        order.feedRule = feedRule;
        order.status = OrderStatus.RFQ_CREATED;
        order.createdAt = block.timestamp;

        buyerOrders[msg.sender].push(orderId);
        ordersByCountry[country].push(orderId);
        ordersByMarket[market].push(orderId);
        ordersByCode[underlyingCode].push(orderId);

        emit OrderCreated(orderId, msg.sender, true, block.timestamp);
        emit OrderStatusChanged(orderId, OrderStatus.RFQ_CREATED, OrderStatus.RFQ_CREATED, "created", block.timestamp);

        return orderId;
    }

    /**
     * @notice 买方选择卖方报价成交
     */
    function acceptQuote(uint256 quoteId) external override nonReentrant whenNotPaused {
        Quote storage quote = quotes[quoteId];
        require(quote.status == QuoteStatus.Active, "OptionsCore: quote not active");
        require(block.timestamp <= quote.expiresAt, "OptionsCore: quote expired");

        Order storage order = orders[quote.orderId];
        require(msg.sender == order.buyer, "OptionsCore: not buyer");

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.MATCHED;
        order.seller = quote.seller;
        order.premiumAmount = quote.premiumAmount;
        order.initialMargin = quote.marginAmount;
        order.currentMargin = quote.marginAmount;
        order.liquidationRule = quote.liquidationRule;
        order.consecutiveDays = quote.consecutiveDays;
        order.dailyLimitPercent = quote.dailyLimitPercent;
        order.matchedAt = block.timestamp;

        uint256 tradingFee = (order.notionalUSDT * config.tradingFeeRate()) / 10000;
        // 权利金存入买方保证金账户（结算时由 transferMargin 划给卖方）
        vaultManager.depositMargin(msg.sender, address(usdt), quote.premiumAmount);
        // 交易手续费入利润池
        vaultManager.collectFee(msg.sender, address(usdt), tradingFee, "trading_fee");

        sellerOrders[quote.seller].push(order.orderId);

        // 将其他报价设为拒绝
        Quote[] storage allQuotes = orderQuotes[order.orderId];
        for (uint256 i = 0; i < allQuotes.length; i++) {
            if (allQuotes[i].quoteId != quoteId && allQuotes[i].status == QuoteStatus.Active) {
                allQuotes[i].status = QuoteStatus.Rejected;
            }
        }

        emit OrderMatched(order.orderId, order.buyer, order.seller, block.timestamp);
        emit OrderStatusChanged(order.orderId, oldStatus, OrderStatus.MATCHED, "quote accepted", block.timestamp);
    }

    /**
     * @notice 买方直接承接卖方挂单
     */
    function acceptSellerOrder(uint256 orderId) external 
        validOrder(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(order.status == OrderStatus.RFQ_CREATED, "OptionsCore: order not available");
        require(order.seller != address(0), "OptionsCore: not a seller order");
        require(msg.sender != order.seller, "OptionsCore: cannot accept own order");

        order.buyer = msg.sender;
        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.MATCHED;
        order.matchedAt = block.timestamp;

        uint256 tradingFee = (order.notionalUSDT * config.tradingFeeRate()) / 10000;
        // 权利金存入买方保证金账户（结算时由 transferMargin 划给卖方）
        vaultManager.depositMargin(msg.sender, address(usdt), order.premiumAmount);
        // 交易手续费入利润池
        vaultManager.collectFee(msg.sender, address(usdt), tradingFee, "trading_fee");

        buyerOrders[msg.sender].push(orderId);
        
        emit OrderMatched(order.orderId, order.buyer, order.seller, block.timestamp);
        emit OrderStatusChanged(order.orderId, oldStatus, OrderStatus.MATCHED, "seller order accepted", block.timestamp);
    }

    /**
     * @notice 买方发起喂价请求（发射事件供 FeedEngine 监听）
     */
    function requestFeed(uint256 orderId, FeedTier tier) external payable override 
        validOrder(orderId) 
        onlyBuyer(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];

        FeedType feedType;
        if (order.status == OrderStatus.MATCHED) {
            feedType = FeedType.Initial;
            OrderStatus oldStatus = order.status;
            order.status = OrderStatus.WAITING_INITIAL_FEED;
            emit OrderStatusChanged(orderId, oldStatus, OrderStatus.WAITING_INITIAL_FEED, "initial feed requested", block.timestamp);
        } else if (order.status == OrderStatus.WAITING_FINAL_FEED) {
            feedType = FeedType.Final;
        } else if (order.status == OrderStatus.LIVE) {
            feedType = FeedType.Dynamic;
        } else {
            revert("OptionsCore: invalid status for feed request");
        }

        emit FeedRequestEmitted(
            orderId,
            order.underlyingCode,
            order.market,
            order.country,
            feedType,
            tier,
            msg.sender,
            order.notionalUSDT,
            block.timestamp
        );
    }

    /**
     * @notice 买方取消未成交的RFQ
     * @dev QUOTING 状态下需退还所有卖方报价保证金
     */
    function cancelRFQ(uint256 orderId) external override 
        validOrder(orderId) 
        onlyBuyer(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(
            order.status == OrderStatus.RFQ_CREATED || order.status == OrderStatus.QUOTING,
            "OptionsCore: cannot cancel after match"
        );

        // QUOTING 状态下退还所有卖方报价保证金
        if (order.status == OrderStatus.QUOTING) {
            _refundAllQuoteMargins(orderId);
        }

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.CANCELLED;

        emit OrderCancelled(orderId, "buyer cancelled", block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.CANCELLED, "buyer cancelled", block.timestamp);
    }

    /**
     * @notice RFQ 超时未成交自动取消
     * @dev 超过 rfqValidityPeriod 后任何人可触发
     */
    function cancelRFQDueToTimeout(uint256 orderId) external 
        validOrder(orderId)
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(
            order.status == OrderStatus.RFQ_CREATED || order.status == OrderStatus.QUOTING,
            "OptionsCore: not in RFQ phase"
        );
        require(
            block.timestamp > order.createdAt + config.rfqValidityPeriod(),
            "OptionsCore: RFQ not expired yet"
        );

        // 退还所有卖方报价保证金
        if (order.status == OrderStatus.QUOTING) {
            _refundAllQuoteMargins(orderId);
        }

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.CANCELLED;

        emit OrderCancelled(orderId, "rfq timeout", block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.CANCELLED, "rfq timeout", block.timestamp);
    }

    /**
     * @notice 内部函数：退还订单所有报价的卖方保证金
     */
    function _refundAllQuoteMargins(uint256 orderId) internal {
        Quote[] storage allQuotes = orderQuotes[orderId];
        for (uint256 i = 0; i < allQuotes.length; i++) {
            Quote storage q = allQuotes[i];
            if (q.status == QuoteStatus.Active && q.marginAmount > 0) {
                q.status = QuoteStatus.Expired;
                vaultManager.withdrawMargin(q.seller, address(usdt), q.marginAmount);
                emit QuoteMarginRefunded(orderId, q.quoteId, q.seller, q.marginAmount, block.timestamp);
            }
        }
    }

    // ==================== 卖方功能 ====================

    /**
     * @notice 卖方创建卖单
     */
    function createSellerOrder(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 premiumRate,
        uint256 marginAmount,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent,
        uint256 arbitrationWindow,
        bool dividendAdjustment,
        uint8 exerciseDelay,
        FeedRule feedRule
    ) external override nonReentrant whenNotPaused returns (uint256 orderId) {
        require(notionalUSDT > 0, "OptionsCore: notional must be positive");
        require(expiryTimestamp > block.timestamp, "OptionsCore: expiry must be in future");

        // 手续费入利润池，保证金入卖方保证金账户
        vaultManager.collectFee(msg.sender, address(usdt), config.creationFee(), "creation_fee");
        vaultManager.depositMargin(msg.sender, address(usdt), marginAmount);

        orderId = nextOrderId++;
        Order storage order = orders[orderId];
        order.orderId = orderId;
        order.seller = msg.sender;
        order.underlyingName = underlyingName;
        order.underlyingCode = underlyingCode;
        order.market = market;
        order.country = country;
        order.refPrice = refPrice;
        order.direction = direction;
        order.notionalUSDT = notionalUSDT;
        order.expiryTimestamp = expiryTimestamp;
        order.premiumAmount = (notionalUSDT * premiumRate) / 10000;
        order.initialMargin = marginAmount;
        order.currentMargin = marginAmount;
        order.liquidationRule = liquidationRule;
        order.consecutiveDays = consecutiveDays;
        order.dailyLimitPercent = dailyLimitPercent;
        order.arbitrationWindow = arbitrationWindow;
        order.dividendAdjustment = dividendAdjustment;
        order.exerciseDelay = exerciseDelay;
        order.feedRule = feedRule;
        order.status = OrderStatus.RFQ_CREATED;
        order.createdAt = block.timestamp;

        sellerOrders[msg.sender].push(orderId);
        ordersByCountry[country].push(orderId);
        ordersByMarket[market].push(orderId);
        ordersByCode[underlyingCode].push(orderId);

        emit OrderCreated(orderId, msg.sender, false, block.timestamp);
        emit OrderStatusChanged(orderId, OrderStatus.RFQ_CREATED, OrderStatus.RFQ_CREATED, "seller order created", block.timestamp);

        return orderId;
    }

    /**
     * @notice 卖方对买方RFQ报价
     */
    function submitQuote(
        uint256 orderId,
        uint256 premiumRate,
        uint256 marginRate,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent
    ) external override validOrder(orderId) nonReentrant whenNotPaused returns (uint256 quoteId) {
        Order storage order = orders[orderId];
        require(
            order.status == OrderStatus.RFQ_CREATED || order.status == OrderStatus.QUOTING,
            "OptionsCore: order not accepting quotes"
        );

        uint256 premiumAmount = (order.notionalUSDT * premiumRate) / 10000;
        uint256 marginAmount = (order.notionalUSDT * marginRate) / 10000;

        if (order.maxPremiumRate > 0) {
            require(premiumRate <= order.maxPremiumRate, "OptionsCore: premium rate too high");
        }
        require(marginRate >= order.minMarginRate, "OptionsCore: margin rate too low");

        // 报价保证金入卖方保证金账户
        vaultManager.depositMargin(msg.sender, address(usdt), marginAmount);

        quoteId = nextQuoteId++;

        Quote memory quote = Quote({
            quoteId: quoteId,
            orderId: orderId,
            seller: msg.sender,
            sellerType: SellerType.FreeSeller,
            premiumRate: premiumRate,
            premiumAmount: premiumAmount,
            marginRate: marginRate,
            marginAmount: marginAmount,
            createdAt: block.timestamp,
            expiresAt: block.timestamp + config.quoteValidityPeriod(),
            status: QuoteStatus.Active,
            liquidationRule: liquidationRule,
            consecutiveDays: consecutiveDays,
            dailyLimitPercent: dailyLimitPercent
        });

        quotes[quoteId] = quote;
        orderQuotes[orderId].push(quote);

        if (order.status == OrderStatus.RFQ_CREATED) {
            order.status = OrderStatus.QUOTING;
        }

        emit QuoteSubmitted(orderId, quoteId, msg.sender, premiumRate, block.timestamp);

        return quoteId;
    }

    // ==================== Settlement 跨合约写入接口 ====================

    /**
     * @notice 更新订单状态（仅 Settlement 合约可调用）
     */
    function updateOrderStatus(uint256 orderId, OrderStatus newStatus) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].status = newStatus;
    }

    /**
     * @notice 更新订单保证金（仅 Settlement 合约可调用）
     */
    function updateOrderMargin(uint256 orderId, uint256 newMargin) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].currentMargin = newMargin;
    }

    /**
     * @notice 更新订单价格（仅 Settlement 合约可调用）
     */
    function updateOrderPrice(uint256 orderId, uint256 newPrice) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].lastFeedPrice = newPrice;
    }

    /**
     * @notice 更新订单结算时间（仅 Settlement 合约可调用）
     */
    function updateOrderSettledAt(uint256 orderId, uint256 timestamp) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].settledAt = timestamp;
    }

    /**
     * @notice 更新追保截止时间（仅 Settlement 合约可调用）
     */
    function updateOrderMarginCallDeadline(uint256 orderId, uint256 deadline) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].marginCallDeadline = deadline;
    }

    /**
     * @notice 更新订单累计分红（仅 Settlement 合约可调用）
     */
    function updateOrderDividend(uint256 orderId, uint256 amount) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].dividendAmount = amount;
    }

    /**
     * @notice 更新订单行权价（仅 Settlement 合约可调用）
     */
    function updateOrderStrikePrice(uint256 orderId, uint256 price) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].strikePrice = price;
    }

    // ==================== 查询功能 ====================

    function getOrder(uint256 orderId) external view override returns (Order memory) {
        return orders[orderId];
    }

    function getQuotes(uint256 orderId) external view override returns (Quote[] memory) {
        return orderQuotes[orderId];
    }

    function getBuyerOrders(address buyer) external view override returns (uint256[] memory) {
        return buyerOrders[buyer];
    }

    function getSellerOrders(address seller) external view override returns (uint256[] memory) {
        return sellerOrders[seller];
    }

    function getOrdersByCountry(string calldata country) external view returns (uint256[] memory) {
        return ordersByCountry[country];
    }

    function getOrdersByMarket(string calldata market) external view returns (uint256[] memory) {
        return ordersByMarket[market];
    }

    // ==================== 管理功能 ====================

    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    function setVaultManager(address _vaultManager) external onlyRole(DEFAULT_ADMIN_ROLE) {
        vaultManager = VaultManager(_vaultManager);
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    // ==================== 喂价回调 ====================

    /**
     * @notice [DEPRECATED] 处理期初喂价结果 — admin 紧急/手动使用
     * @dev 内部转发到 _processFeedCallbackInternal，逻辑与 processFeedCallback(Initial) 一致
     *      正式路径请使用 FeedProtocol 自动回调 processFeedCallback
     */
    function processInitialFeedResult(
        uint256 orderId, 
        uint256 initialPrice
    ) external validOrder(orderId) onlyRole(DEFAULT_ADMIN_ROLE) {
        _processFeedCallbackInternal(orderId, FeedType.Initial, initialPrice);
    }

    /**
     * @notice [DEPRECATED] 处理期末喂价结果 — admin 紧急/手动使用
     * @dev 内部转发到 _processFeedCallbackInternal，逻辑与 processFeedCallback(Final) 一致
     *      正式路径请使用 FeedProtocol 自动回调 processFeedCallback
     */
    function processFinalFeedResult(
        uint256 orderId, 
        uint256 finalPrice
    ) external validOrder(orderId) onlyRole(DEFAULT_ADMIN_ROLE) {
        _processFeedCallbackInternal(orderId, FeedType.Final, finalPrice);
    }

    /**
     * @notice FeedProtocol 通知：已创建喂价请求，同步更新订单状态
     * @dev 当前端通过 FeedProtocol.requestFeedPublic 发起喂价时，
     *      FeedProtocol 调用此函数同步 OptionsCore 订单状态，
     *      确保链上状态与 UI 状态一致
     *      Initial  → MATCHED → WAITING_INITIAL_FEED
     *      Dynamic  → LIVE（不变）
     *      Final    → LIVE → WAITING_FINAL_FEED（如当前是 LIVE）
     */
    function onFeedRequested(
        uint256 orderId,
        FeedType feedType
    ) external override validOrder(orderId) onlyRole(FEED_PROTOCOL_ROLE) {
        Order storage order = orders[orderId];

        if (feedType == FeedType.Initial) {
            if (order.status == OrderStatus.MATCHED) {
                OrderStatus oldStatus = order.status;
                order.status = OrderStatus.WAITING_INITIAL_FEED;
                emit OrderStatusChanged(orderId, oldStatus, OrderStatus.WAITING_INITIAL_FEED, "feed requested via FeedProtocol", block.timestamp);
            }
            // 已经是 WAITING_INITIAL_FEED 则不重复变更
        } else if (feedType == FeedType.Final) {
            if (order.status == OrderStatus.LIVE) {
                OrderStatus oldStatus = order.status;
                order.status = OrderStatus.WAITING_FINAL_FEED;
                emit OrderStatusChanged(orderId, oldStatus, OrderStatus.WAITING_FINAL_FEED, "final feed requested via FeedProtocol", block.timestamp);
            }
        }
        // Dynamic 和 Arbitration 不需要状态变更
    }

    /**
     * @notice FeedEngine 喂价完成后自动回调（正式路径）
     * @dev 处理四种喂价类型：
     *      Initial  → 设置行权价 + lastFeedPrice，状态 → LIVE
     *      Dynamic  → 仅更新 lastFeedPrice，状态保持 LIVE（用于保证金风控）
     *      Final    → 更新 lastFeedPrice，状态 → PENDING_SETTLEMENT
     *      Arbitration → 更新 lastFeedPrice，状态 → PENDING_SETTLEMENT
     */
    function processFeedCallback(
        uint256 orderId, 
        FeedType feedType, 
        uint256 finalPrice
    ) external override validOrder(orderId) onlyRole(FEED_PROTOCOL_ROLE) {
        _processFeedCallbackInternal(orderId, feedType, finalPrice);
    }

    /**
     * @dev 统一的喂价结果处理内部函数
     *      所有外部入口（processFeedCallback / processInitialFeedResult / processFinalFeedResult）
     *      都转发到此函数，确保状态变更逻辑唯一
     */
    function _processFeedCallbackInternal(
        uint256 orderId,
        FeedType feedType,
        uint256 finalPrice
    ) internal {
        Order storage order = orders[orderId];
        require(finalPrice > 0, "OptionsCore: invalid price");

        if (feedType == FeedType.Initial) {
            require(
                order.status == OrderStatus.MATCHED || order.status == OrderStatus.WAITING_INITIAL_FEED,
                "OptionsCore: not awaiting initial feed"
            );
            order.strikePrice = finalPrice;
            order.lastFeedPrice = finalPrice;
            OrderStatus oldStatus = order.status;
            order.status = OrderStatus.LIVE;
            emit OrderStatusChanged(orderId, oldStatus, OrderStatus.LIVE, "initial feed callback", block.timestamp);

        } else if (feedType == FeedType.Dynamic) {
            require(
                order.status == OrderStatus.LIVE,
                "OptionsCore: dynamic feed only for LIVE orders"
            );
            order.lastFeedPrice = finalPrice;
            emit OrderStatusChanged(orderId, OrderStatus.LIVE, OrderStatus.LIVE, "dynamic feed callback", block.timestamp);

        } else if (feedType == FeedType.Final) {
            require(
                order.status == OrderStatus.LIVE || order.status == OrderStatus.WAITING_FINAL_FEED,
                "OptionsCore: not awaiting final feed"
            );
            order.lastFeedPrice = finalPrice;
            OrderStatus oldStatus = order.status;
            order.status = OrderStatus.PENDING_SETTLEMENT;
            order.settledAt = block.timestamp;
            emit OrderStatusChanged(orderId, oldStatus, OrderStatus.PENDING_SETTLEMENT, "final feed callback", block.timestamp);

        } else if (feedType == FeedType.Arbitration) {
            require(
                order.status == OrderStatus.ARBITRATION,
                "OptionsCore: not in arbitration"
            );
            order.lastFeedPrice = finalPrice;
            OrderStatus oldStatus = order.status;
            order.status = OrderStatus.PENDING_SETTLEMENT;
            order.settledAt = block.timestamp;
            emit OrderStatusChanged(orderId, oldStatus, OrderStatus.PENDING_SETTLEMENT, "arbitration feed callback", block.timestamp);
        }
    }

    /**
     * @notice 将 uint256 转换为字符串
     */
    function _uintToString(uint256 value) internal pure returns (string memory) {
        if (value == 0) {
            return "0";
        }
        uint256 temp = value;
        uint256 digits;
        while (temp != 0) {
            digits++;
            temp /= 10;
        }
        bytes memory buffer = new bytes(digits);
        while (value != 0) {
            digits -= 1;
            buffer[digits] = bytes1(uint8(48 + uint256(value % 10)));
            value /= 10;
        }
        return string(buffer);
    }
}

contracts/feed/FeedProtocol.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../libraries/NSTTypes.sol";
import "../interfaces/IFeedProtocol.sol";
import "../interfaces/IOptionsCore.sol";
import "../core/Config.sol";

/**
 * @title FeedProtocol
 * @notice 独立喂价协议 - 喂价请求、喂价提交、结果聚合
 * @dev 与期权协议完全分离，可服务于多种协议
 */
contract FeedProtocol is IFeedProtocol, AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 角色定义 ====================
    bytes32 public constant FEED_OPERATOR_ROLE = keccak256("FEED_OPERATOR_ROLE");
    bytes32 public constant PROTOCOL_ROLE = keccak256("PROTOCOL_ROLE");  // 可调用的协议合约
    bytes32 public constant SENIOR_FEEDER_ROLE = keccak256("SENIOR_FEEDER_ROLE");  // 高级喂价员（仲裁用）

    // ==================== 状态变量 ====================
    Config public config;
    IERC20 public usdt;
    
    // OptionsCore 引用（用于自动回调）
    IOptionsCore public optionsCore;
    
    // [P2预留] FeederSelector (Chainlink VRF V2.5) 链上随机选择，MVP 阶段由链下 FeedEngine 服务分配
    address public feederSelector;

    uint256 public nextRequestId = 1;

    // 喂价请求存储
    mapping(uint256 => FeedRequest) public feedRequests;
    
    // 喂价请求的提交记录
    struct FeedSubmission {
        address feeder;
        uint256 price;
        uint256 timestamp;
        bool isValid;
    }
    mapping(uint256 => FeedSubmission[]) public requestSubmissions;
    mapping(uint256 => mapping(address => bool)) public hasSubmitted;

    // 喂价员注册
    struct Feeder {
        address feederAddress;
        uint256 stakedAmount;
        uint256 completedFeeds;
        uint256 rejectedFeeds;
        uint256 registeredAt;
        bool isActive;
        bool isBlacklisted;
    }
    mapping(address => Feeder) public feeders;
    address[] public feederList;

    // 喂价档位配置
    struct FeedTierConfig {
        uint8 totalFeeders;
        uint8 effectiveFeeds;
        uint256 platformFee;
        uint256 feederReward;
        uint256 totalFee;
    }
    mapping(FeedTier => FeedTierConfig) public tierConfigs;

    // 订单关联的喂价请求
    mapping(uint256 => uint256[]) public orderFeedRequests;

    // ==================== 事件 ====================
    event FeederRegistered(
        address indexed feeder,
        uint256 stakedAmount,
        uint256 timestamp
    );

    event FeederDeactivated(
        address indexed feeder,
        string reason,
        uint256 timestamp
    );

    event FeederBlacklisted(
        address indexed feeder,
        string reason,
        uint256 timestamp
    );

    event RewardDistributed(
        uint256 indexed requestId,
        address indexed feeder,
        uint256 amount,
        uint256 timestamp
    );

    event OptionsCoreUpdated(
        address indexed oldAddress,
        address indexed newAddress,
        uint256 timestamp
    );

    event CallbackFailed(
        uint256 indexed requestId,
        uint256 indexed orderId,
        string reason
    );

    event FeedFinalizeSkipped(
        uint256 indexed requestId,
        string reason
    );

    // ==================== 构造函数 ====================
    constructor(
        address _config,
        address _usdt,
        address _admin
    ) {
        config = Config(_config);
        usdt = IERC20(_usdt);
        
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(FEED_OPERATOR_ROLE, _admin);

        // 初始化喂价档位配置
        _initTierConfigs();
    }

    function _initTierConfigs() internal {
        // 5-3档：5个喂价员，取3个有效中位数
        tierConfigs[FeedTier.Tier_5_3] = FeedTierConfig({
            totalFeeders: 5,
            effectiveFeeds: 3,
            platformFee: 0.3 ether,     // 10% = 0.3U
            feederReward: 2.7 ether,    // 90% = 2.7U
            totalFee: 3 ether
        });

        // 7-5档：5U
        tierConfigs[FeedTier.Tier_7_5] = FeedTierConfig({
            totalFeeders: 7,
            effectiveFeeds: 5,
            platformFee: 0.5 ether,
            feederReward: 4.5 ether,
            totalFee: 5 ether
        });

        // 10-7档：8U
        tierConfigs[FeedTier.Tier_10_7] = FeedTierConfig({
            totalFeeders: 10,
            effectiveFeeds: 7,
            platformFee: 0.8 ether,
            feederReward: 7.2 ether,
            totalFee: 8 ether
        });
    }

    /**
     * @notice 设置 OptionsCore 地址（用于自动回调）
     * @param _optionsCore OptionsCore 合约地址
     */
    function setOptionsCore(address _optionsCore) external onlyRole(DEFAULT_ADMIN_ROLE) {
        address oldAddress = address(optionsCore);
        optionsCore = IOptionsCore(_optionsCore);
        emit OptionsCoreUpdated(oldAddress, _optionsCore, block.timestamp);
    }

    /**
     * @notice 更新喂价档位配置 (管理员)
     */
    function setTierConfig(
        FeedTier tier,
        uint8 totalFeeders,
        uint8 effectiveFeeds,
        uint256 platformFee,
        uint256 feederReward,
        uint256 totalFee
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        tierConfigs[tier] = FeedTierConfig({
            totalFeeders: totalFeeders,
            effectiveFeeds: effectiveFeeds,
            platformFee: platformFee,
            feederReward: feederReward,
            totalFee: totalFee
        });
    }

    // ==================== 修改器 ====================
    modifier onlyOperator() {
        require(hasRole(FEED_OPERATOR_ROLE, msg.sender), "FeedProtocol: not operator");
        _;
    }

    modifier onlyProtocol() {
        require(hasRole(PROTOCOL_ROLE, msg.sender), "FeedProtocol: not authorized protocol");
        _;
    }

    modifier onlyActiveFeeder() {
        require(feeders[msg.sender].isActive, "FeedProtocol: not active feeder");
        require(!feeders[msg.sender].isBlacklisted, "FeedProtocol: feeder blacklisted");
        require(
            feeders[msg.sender].stakedAmount >= config.minFeederStake(),
            "FeedProtocol: insufficient stake"
        );
        _;
    }

    modifier validRequest(uint256 requestId) {
        require(requestId > 0 && requestId < nextRequestId, "FeedProtocol: invalid request");
        _;
    }

    // ==================== 喂价员注册 ====================

    /**
     * @notice 注册为喂价员
     * @param stakeAmount 质押金额（最低100U）
     */
    function registerFeeder(uint256 stakeAmount) external nonReentrant whenNotPaused {
        require(feeders[msg.sender].feederAddress == address(0), "FeedProtocol: already registered");
        require(stakeAmount >= config.minFeederStake(), "FeedProtocol: insufficient stake");

        usdt.safeTransferFrom(msg.sender, address(this), stakeAmount);

        feeders[msg.sender] = Feeder({
            feederAddress: msg.sender,
            stakedAmount: stakeAmount,
            completedFeeds: 0,
            rejectedFeeds: 0,
            registeredAt: block.timestamp,
            isActive: true,
            isBlacklisted: false
        });

        feederList.push(msg.sender);

        emit FeederRegistered(msg.sender, stakeAmount, block.timestamp);
    }

    /**
     * @notice 追加质押
     */
    function addStake(uint256 amount) external nonReentrant whenNotPaused {
        require(feeders[msg.sender].feederAddress != address(0), "FeedProtocol: not registered");
        
        usdt.safeTransferFrom(msg.sender, address(this), amount);
        feeders[msg.sender].stakedAmount += amount;
    }

    /**
     * @notice 提取质押（需无进行中的喂价任务）
     */
    function withdrawStake(uint256 amount) external nonReentrant whenNotPaused {
        Feeder storage feeder = feeders[msg.sender];
        require(feeder.stakedAmount >= amount, "FeedProtocol: insufficient stake");
        require(
            feeder.stakedAmount - amount >= config.minFeederStake() || amount == feeder.stakedAmount,
            "FeedProtocol: must maintain min stake or withdraw all"
        );

        feeder.stakedAmount -= amount;
        if (feeder.stakedAmount == 0) {
            feeder.isActive = false;
        }
        
        usdt.safeTransfer(msg.sender, amount);
    }

    // ==================== 喂价请求 ====================

    /**
     * @notice 创建喂价请求（由期权协议调用）
     */
    function createFeedRequest(
        uint256 orderId,
        FeedType feedType,
        FeedTier tier
    ) external payable override onlyProtocol nonReentrant returns (uint256 requestId) {
        FeedTierConfig memory tierConfig = tierConfigs[tier];
        
        // 收取喂价费用
        usdt.safeTransferFrom(msg.sender, address(this), tierConfig.totalFee);

        requestId = nextRequestId++;

        feedRequests[requestId] = FeedRequest({
            requestId: requestId,
            orderId: orderId,
            feedType: feedType,
            tier: tier,
            deadline: block.timestamp + _getFeedDeadline(feedType),
            createdAt: block.timestamp,
            totalFeeders: tierConfig.totalFeeders,
            submittedCount: 0,
            finalPrice: 0,
            finalized: false
        });

        orderFeedRequests[orderId].push(requestId);

        // [架构说明] 喂价员分配由链下 FeedEngine 服务完成（MVP 阶段）
        // FeederSelector(Chainlink VRF V2.5) 随机选择为 P2 阶段预留模块

        emit FeedRequested(
            requestId,
            orderId,
            "",  // underlyingName 需要从订单获取
            "",  // underlyingCode
            "",  // market
            "",  // country
            feedType,
            LiquidationRule.NoLiquidation,
            0,   // consecutiveDays
            0,   // exerciseDelay
            block.timestamp
        );

        return requestId;
    }

    /**
     * @notice 创建喂价请求（公开版本，MVP演示用）
     * @dev 允许任何地址发起喂价请求，需支付 USDT 喂价费用
     * @param orderId 订单ID
     * @param feedType 喂价类型 (期初/动态/期末/仲裁)
     * @param tier 喂价档位 (5-3/7-5/10-7)
     */
    function requestFeedPublic(
        uint256 orderId,
        FeedType feedType,
        FeedTier tier
    ) external nonReentrant whenNotPaused returns (uint256 requestId) {
        FeedTierConfig memory tierConfig = tierConfigs[tier];
        
        // 收取喂价费用
        usdt.safeTransferFrom(msg.sender, address(this), tierConfig.totalFee);

        requestId = nextRequestId++;

        feedRequests[requestId] = FeedRequest({
            requestId: requestId,
            orderId: orderId,
            feedType: feedType,
            tier: tier,
            deadline: block.timestamp + _getFeedDeadline(feedType),
            createdAt: block.timestamp,
            totalFeeders: tierConfig.totalFeeders,
            submittedCount: 0,
            finalPrice: 0,
            finalized: false
        });

        orderFeedRequests[orderId].push(requestId);

        // 从 OptionsCore 读取订单信息填充事件（而非发送空字符串）
        Order memory order = optionsCore.getOrder(orderId);

        emit FeedRequested(
            requestId,
            orderId,
            order.underlyingName,
            order.underlyingCode,
            order.market,
            order.country,
            feedType,
            order.liquidationRule,
            order.consecutiveDays,
            order.exerciseDelay,
            block.timestamp
        );

        // 同步更新 OptionsCore 订单状态（MATCHED→WAITING_INITIAL_FEED 等）
        try optionsCore.onFeedRequested(orderId, feedType) {
            // 状态已同步
        } catch {
            // 状态同步失败不阻止喂价请求创建（幂等 / 状态已正确）
        }

        return requestId;
    }

    /**
     * @notice 喂价员提交喂价
     */
    function submitFeed(
        uint256 requestId,
        uint256 price
    ) external override validRequest(requestId) onlyActiveFeeder nonReentrant whenNotPaused {
        FeedRequest storage request = feedRequests[requestId];
        require(!request.finalized, "FeedProtocol: already finalized");
        require(block.timestamp <= request.deadline, "FeedProtocol: request expired");
        require(!hasSubmitted[requestId][msg.sender], "FeedProtocol: already submitted");
        require(price > 0, "FeedProtocol: price must be positive");

        hasSubmitted[requestId][msg.sender] = true;
        request.submittedCount++;

        requestSubmissions[requestId].push(FeedSubmission({
            feeder: msg.sender,
            price: price,
            timestamp: block.timestamp,
            isValid: true
        }));

        emit FeedSubmitted(requestId, msg.sender, price, block.timestamp);

        // 检查是否达到所需数量
        if (request.submittedCount >= request.totalFeeders) {
            _finalizeFeed(requestId);
        }
    }

    /**
     * @notice 喂价员拒绝喂价
     * @dev 拒绝也计入 submittedCount，当所有喂价员都响应后（提交或拒绝），
     *      自动尝试 finalize。如果有效报价不足 effectiveFeeds，emit 跳过事件，
     *      请求保持 un-finalized，最终通过 cancelOrderDueToFeedTimeout 清理。
     */
    function rejectFeed(
        uint256 requestId,
        string calldata reason
    ) external override validRequest(requestId) onlyActiveFeeder nonReentrant whenNotPaused {
        FeedRequest storage request = feedRequests[requestId];
        require(!request.finalized, "FeedProtocol: already finalized");
        require(!hasSubmitted[requestId][msg.sender], "FeedProtocol: already submitted");

        hasSubmitted[requestId][msg.sender] = true;
        request.submittedCount++;
        feeders[msg.sender].rejectedFeeds++;

        emit FeedRejected(requestId, msg.sender, reason, block.timestamp);

        // 所有喂价员都已响应（提交或拒绝），检查是否可以 finalize
        if (request.submittedCount >= request.totalFeeders) {
            // 统计有效报价数
            FeedSubmission[] storage submissions = requestSubmissions[requestId];
            uint256 validCount = 0;
            for (uint256 i = 0; i < submissions.length; i++) {
                if (submissions[i].isValid && submissions[i].price > 0) {
                    validCount++;
                }
            }

            FeedTierConfig memory tierConfig = tierConfigs[request.tier];
            if (validCount >= tierConfig.effectiveFeeds) {
                // 有效报价达标，自动 finalize
                _finalizeFeed(requestId);
            } else {
                // 有效报价不足，请求保持 open 等待超时清理
                emit FeedFinalizeSkipped(requestId, "insufficient valid feeds after all responses");
            }
        }
    }

    /**
     * @notice 外部触发的喂价聚合（取中间位）
     * @dev 仅在 deadline 过期后才允许外部调用；
     *      submitFeed 达到 totalFeeders 时会自动内部调用 _finalizeFeed
     */
    function finalizeFeed(uint256 requestId) external override returns (uint256 finalPrice) {
        FeedRequest storage request = feedRequests[requestId];
        require(!request.finalized, "FeedProtocol: already finalized");
        // 外部调用必须等 deadline 过期，防止提前被任意地址抢跑
        require(block.timestamp > request.deadline, "FeedProtocol: deadline not reached");
        return _finalizeFeed(requestId);
    }

    /**
     * @notice 内部喂价聚合 — 强制要求有效报价数 >= effectiveFeeds
     * @dev 排序后取中位数；不满足门槛则 revert
     */
    function _finalizeFeed(uint256 requestId) internal returns (uint256 finalPrice) {
        FeedRequest storage request = feedRequests[requestId];
        require(!request.finalized, "FeedProtocol: already finalized");

        FeedSubmission[] storage submissions = requestSubmissions[requestId];
        require(submissions.length > 0, "FeedProtocol: no submissions");

        // ── 收集有效价格 ──
        uint256[] memory prices = new uint256[](submissions.length);
        uint256 validCount = 0;
        
        for (uint256 i = 0; i < submissions.length; i++) {
            if (submissions[i].isValid && submissions[i].price > 0) {
                prices[validCount] = submissions[i].price;
                validCount++;
            }
        }

        // ── 强制执行档位门槛：有效报价数 >= effectiveFeeds ──
        FeedTierConfig memory tierConfig = tierConfigs[request.tier];
        require(
            validCount >= tierConfig.effectiveFeeds,
            "FeedProtocol: insufficient valid feeds for tier"
        );

        // ── 排序价格 ──
        for (uint256 i = 0; i < validCount - 1; i++) {
            for (uint256 j = 0; j < validCount - i - 1; j++) {
                if (prices[j] > prices[j + 1]) {
                    uint256 temp = prices[j];
                    prices[j] = prices[j + 1];
                    prices[j + 1] = temp;
                }
            }
        }

        // ── 取中位数 ──
        if (validCount % 2 == 0) {
            finalPrice = (prices[validCount / 2 - 1] + prices[validCount / 2]) / 2;
        } else {
            finalPrice = prices[validCount / 2];
        }

        request.finalPrice = finalPrice;
        request.finalized = true;

        // 分发奖励
        _distributeRewards(requestId, submissions);

        emit FeedFinalized(requestId, finalPrice, block.timestamp);

        // 自动回调 OptionsCore 更新订单状态
        if (address(optionsCore) != address(0)) {
            try optionsCore.processFeedCallback(request.orderId, request.feedType, finalPrice) {
                // 回调成功
            } catch {
                // 回调失败时不 revert 整个交易，只记录事件
                emit CallbackFailed(requestId, request.orderId, "OptionsCore callback failed");
            }
        }

        return finalPrice;
    }

    /**
     * @notice 分发喂价奖励
     */
    function _distributeRewards(uint256 requestId, FeedSubmission[] storage submissions) internal {
        FeedRequest storage request = feedRequests[requestId];
        FeedTierConfig memory tierConfig = tierConfigs[request.tier];
        
        uint256 rewardPerFeeder = tierConfig.feederReward / submissions.length;

        for (uint256 i = 0; i < submissions.length; i++) {
            if (submissions[i].isValid) {
                address feeder = submissions[i].feeder;
                usdt.safeTransfer(feeder, rewardPerFeeder);
                feeders[feeder].completedFeeds++;
                
                emit RewardDistributed(requestId, feeder, rewardPerFeeder, block.timestamp);
            }
        }

        // 平台费用保留在合约中
    }

    // ==================== 查询功能 ====================

    function getFeedFee(FeedTier tier) external view override returns (uint256) {
        return tierConfigs[tier].totalFee;
    }

    function getFeedRequest(uint256 requestId) external view returns (FeedRequest memory) {
        return feedRequests[requestId];
    }

    function getFeeder(address feeder) external view returns (Feeder memory) {
        return feeders[feeder];
    }

    function getFeederCount() external view returns (uint256) {
        return feederList.length;
    }

    function getOrderFeedRequests(uint256 orderId) external view returns (uint256[] memory) {
        return orderFeedRequests[orderId];
    }

    function getSubmissions(uint256 requestId) external view returns (FeedSubmission[] memory) {
        return requestSubmissions[requestId];
    }

    /**
     * @notice 获取所有待处理（未完成）的喂价请求
     * @return pendingRequests 待处理喂价请求数组
     */
    function getPendingRequests() external view returns (FeedRequest[] memory) {
        // 先统计未完成请求数量
        uint256 pendingCount = 0;
        for (uint256 i = 1; i < nextRequestId; i++) {
            if (!feedRequests[i].finalized && block.timestamp <= feedRequests[i].deadline) {
                pendingCount++;
            }
        }

        // 创建结果数组
        FeedRequest[] memory pendingRequests = new FeedRequest[](pendingCount);
        uint256 index = 0;

        for (uint256 i = 1; i < nextRequestId; i++) {
            if (!feedRequests[i].finalized && block.timestamp <= feedRequests[i].deadline) {
                pendingRequests[index] = feedRequests[i];
                index++;
            }
        }

        return pendingRequests;
    }

    /**
     * @notice 分页获取所有喂价请求
     * @param offset 起始位置
     * @param limit 获取数量
     * @return requests 喂价请求数组
     */
    function getAllFeedRequests(uint256 offset, uint256 limit) external view returns (FeedRequest[] memory) {
        uint256 totalRequests = nextRequestId - 1;
        
        if (offset >= totalRequests) {
            return new FeedRequest[](0);
        }

        uint256 endIndex = offset + limit;
        if (endIndex > totalRequests) {
            endIndex = totalRequests;
        }

        uint256 resultCount = endIndex - offset;
        FeedRequest[] memory requests = new FeedRequest[](resultCount);

        for (uint256 i = 0; i < resultCount; i++) {
            requests[i] = feedRequests[offset + i + 1]; // requestId 从 1 开始
        }

        return requests;
    }

    /**
     * @notice 获取喂价请求总数
     */
    function getTotalRequestCount() external view returns (uint256) {
        return nextRequestId - 1;
    }

    // ==================== VRF 集成功能 (P2 预留) ====================

    /**
     * @notice 获取活跃喂价员列表（供 FeederSelector 使用）
     * @return activeFeeders 活跃喂价员地址数组
     */
    function getActiveFeeders() external view returns (address[] memory) {
        uint256 activeCount = 0;
        
        // 先统计活跃数量
        for (uint256 i = 0; i < feederList.length; i++) {
            if (feeders[feederList[i]].isActive && 
                !feeders[feederList[i]].isBlacklisted &&
                feeders[feederList[i]].stakedAmount >= config.minFeederStake()) {
                activeCount++;
            }
        }
        
        // 创建结果数组
        address[] memory activeFeeders = new address[](activeCount);
        uint256 index = 0;
        
        for (uint256 i = 0; i < feederList.length; i++) {
            if (feeders[feederList[i]].isActive && 
                !feeders[feederList[i]].isBlacklisted &&
                feeders[feederList[i]].stakedAmount >= config.minFeederStake()) {
                activeFeeders[index] = feederList[i];
                index++;
            }
        }
        
        return activeFeeders;
    }

    /**
     * @notice 设置 FeederSelector 地址
     */
    function setFeederSelector(address _feederSelector) external onlyRole(DEFAULT_ADMIN_ROLE) {
        feederSelector = _feederSelector;
    }

    // ==================== 管理功能 ====================

    // ==================== 恶意喂价处理 (P2) ====================

    /// @notice 恶意喂价举报
    struct MaliciousReport {
        uint256 reportId;
        address reporter;           // 举报人
        address reportedFeeder;     // 被举报喂价员
        uint256 requestId;          // 相关喂价请求
        string evidence;            // 证据说明
        uint256 reportedAt;
        bool processed;
        bool confirmed;             // 是否确认恶意
    }
    
    mapping(uint256 => MaliciousReport) public maliciousReports;
    uint256 public nextReportId = 1;
    
    event MaliciousFeedReported(
        uint256 indexed reportId,
        address indexed reporter,
        address indexed feeder,
        uint256 requestId,
        uint256 timestamp
    );
    
    event MaliciousReportProcessed(
        uint256 indexed reportId,
        bool confirmed,
        uint256 slashedAmount,
        uint256 timestamp
    );

    /**
     * @notice 举报恶意喂价
     * @param feeder 被举报的喂价员
     * @param requestId 相关喂价请求ID
     * @param evidence 证据说明
     */
    function reportMaliciousFeed(
        address feeder,
        uint256 requestId,
        string calldata evidence
    ) external nonReentrant whenNotPaused returns (uint256 reportId) {
        require(feeders[feeder].feederAddress != address(0), "FeedProtocol: invalid feeder");
        require(bytes(evidence).length > 0, "FeedProtocol: evidence required");

        reportId = nextReportId++;
        maliciousReports[reportId] = MaliciousReport({
            reportId: reportId,
            reporter: msg.sender,
            reportedFeeder: feeder,
            requestId: requestId,
            evidence: evidence,
            reportedAt: block.timestamp,
            processed: false,
            confirmed: false
        });

        emit MaliciousFeedReported(reportId, msg.sender, feeder, requestId, block.timestamp);
        return reportId;
    }

    /**
     * @notice 处理恶意举报（管理员）
     * @param reportId 举报ID
     * @param confirmed 是否确认恶意
     * @param slashPercent 罚没比例（基点，5000 = 50%）
     */
    function processMaliciousReport(
        uint256 reportId,
        bool confirmed,
        uint256 slashPercent
    ) external onlyOperator nonReentrant {
        MaliciousReport storage report = maliciousReports[reportId];
        require(!report.processed, "FeedProtocol: already processed");
        require(slashPercent <= 10000, "FeedProtocol: invalid slash percent");

        report.processed = true;
        report.confirmed = confirmed;

        uint256 slashedAmount = 0;

        if (confirmed) {
            Feeder storage feeder = feeders[report.reportedFeeder];
            
            // 计算罚没金额
            slashedAmount = (feeder.stakedAmount * slashPercent) / 10000;
            
            if (slashedAmount > 0) {
                feeder.stakedAmount -= slashedAmount;
                // 罚没的押金可转入国库或奖励举报人（此处转入合约作为平台收入）
            }

            // 加入黑名单
            feeder.isBlacklisted = true;
            feeder.isActive = false;
            
            emit FeederBlacklisted(report.reportedFeeder, "malicious feed confirmed", block.timestamp);
        }

        emit MaliciousReportProcessed(reportId, confirmed, slashedAmount, block.timestamp);
    }

    /**
     * @notice 获取举报详情
     */
    function getMaliciousReport(uint256 reportId) external view returns (MaliciousReport memory) {
        return maliciousReports[reportId];
    }

    function grantProtocolRole(address protocol) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(PROTOCOL_ROLE, protocol);
    }

    function grantSeniorFeederRole(address feeder) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(SENIOR_FEEDER_ROLE, feeder);
    }

    function blacklistFeeder(address feeder, string calldata reason) external onlyOperator {
        feeders[feeder].isBlacklisted = true;
        feeders[feeder].isActive = false;
        emit FeederBlacklisted(feeder, reason, block.timestamp);
    }

    /**
     * @notice 根据喂价类型获取对应的超时时限
     * @dev Initial → config.initialFeedDeadline, Final/Dynamic/Arbitration → config.closingFeedDeadline
     */
    function _getFeedDeadline(FeedType feedType) internal view returns (uint256) {
        if (feedType == FeedType.Initial) {
            return config.initialFeedDeadline();
        }
        return config.closingFeedDeadline();
    }

    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    function withdrawPlatformFees(address to) external onlyRole(DEFAULT_ADMIN_ROLE) {
        // 提取平台费用
        uint256 balance = usdt.balanceOf(address(this));
        // 需要减去所有质押金额
        uint256 totalStaked = 0;
        for (uint256 i = 0; i < feederList.length; i++) {
            totalStaked += feeders[feederList[i]].stakedAmount;
        }
        uint256 platformFees = balance > totalStaked ? balance - totalStaked : 0;
        if (platformFees > 0) {
            usdt.safeTransfer(to, platformFees);
        }
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

contracts/interfaces/IFeedProtocol.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "../libraries/NSTTypes.sol";

/**
 * @title IFeedProtocol
 * @notice 喂价协议接口
 */
interface IFeedProtocol {
    // ==================== 事件 ====================
    
    /// @notice 喂价请求事件
    event FeedRequested(
        uint256 indexed requestId,
        uint256 indexed orderId,
        string underlyingName,
        string underlyingCode,
        string market,
        string country,
        FeedType feedType,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 exerciseDelay,
        uint256 timestamp
    );

    /// @notice 喂价提交事件
    event FeedSubmitted(
        uint256 indexed requestId,
        address indexed feeder,
        uint256 price,
        uint256 timestamp
    );

    /// @notice 喂价结果确认事件
    event FeedFinalized(
        uint256 indexed requestId,
        uint256 finalPrice,
        uint256 timestamp
    );

    /// @notice 喂价被拒绝事件
    event FeedRejected(
        uint256 indexed requestId,
        address indexed feeder,
        string reason,
        uint256 timestamp
    );

    // ==================== 函数 ====================

    /// @notice 创建喂价请求
    function createFeedRequest(
        uint256 orderId,
        FeedType feedType,
        FeedTier tier
    ) external payable returns (uint256 requestId);

    /// @notice 喂价员提交喂价
    function submitFeed(uint256 requestId, uint256 price) external;

    /// @notice 喂价员拒绝喂价
    function rejectFeed(uint256 requestId, string calldata reason) external;

    /// @notice 完成喂价聚合
    function finalizeFeed(uint256 requestId) external returns (uint256 finalPrice);

    /// @notice 获取喂价费用
    function getFeedFee(FeedTier tier) external view returns (uint256);
}

contracts/interfaces/IOptionsCore.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "../libraries/NSTTypes.sol";

/**
 * @title IOptionsCore
 * @notice 期权核心合约接口
 * @dev 结算/保证金/仲裁函数已迁移到 IOptionsSettlement
 */
interface IOptionsCore {
    // ==================== 事件 ====================
    event OrderCreated(
        uint256 indexed orderId,
        address indexed creator,
        bool isBuyerOrder,
        uint256 timestamp
    );

    event QuoteSubmitted(
        uint256 indexed orderId,
        uint256 indexed quoteId,
        address indexed seller,
        uint256 premiumRate,
        uint256 timestamp
    );

    event OrderMatched(
        uint256 indexed orderId,
        address indexed buyer,
        address indexed seller,
        uint256 timestamp
    );

    event OrderCancelled(
        uint256 indexed orderId,
        string reason,
        uint256 timestamp
    );

    event OrderStatusChanged(
        uint256 indexed orderId,
        OrderStatus oldStatus,
        OrderStatus newStatus,
        string reason,
        uint256 timestamp
    );

    /// @notice 喂价请求发射事件（供 FeedEngine 监听）
    event FeedRequestEmitted(
        uint256 indexed orderId,
        string underlyingCode,
        string market,
        string country,
        FeedType feedType,
        FeedTier tier,
        address indexed requester,
        uint256 notionalAmount,
        uint256 timestamp
    );

    /// @notice 报价保证金退还事件
    event QuoteMarginRefunded(
        uint256 indexed orderId,
        uint256 indexed quoteId,
        address indexed seller,
        uint256 amount,
        uint256 timestamp
    );

    // ==================== 买方功能 ====================

    function createBuyerRFQ(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 maxPremiumRate,
        uint256 minMarginRate,
        SellerType acceptedSellerType,
        address designatedSeller,
        uint256 arbitrationWindow,
        uint256 marginCallDeadline,
        bool dividendAdjustment,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent,
        FeedRule feedRule
    ) external returns (uint256 orderId);

    function acceptQuote(uint256 quoteId) external;
    function requestFeed(uint256 orderId, FeedTier tier) external payable;
    function cancelRFQ(uint256 orderId) external;

    // ==================== 卖方功能 ====================

    function createSellerOrder(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 premiumRate,
        uint256 marginAmount,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent,
        uint256 arbitrationWindow,
        bool dividendAdjustment,
        uint8 exerciseDelay,
        FeedRule feedRule
    ) external returns (uint256 orderId);

    function submitQuote(
        uint256 orderId,
        uint256 premiumRate,
        uint256 marginRate,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent
    ) external returns (uint256 quoteId);

    // ==================== 查询功能 ====================

    function getOrder(uint256 orderId) external view returns (Order memory);
    function getQuotes(uint256 orderId) external view returns (Quote[] memory);
    function getBuyerOrders(address buyer) external view returns (uint256[] memory);
    function getSellerOrders(address seller) external view returns (uint256[] memory);

    // ==================== 喂价回调 ====================
    
    function processFeedCallback(
        uint256 orderId, 
        FeedType feedType, 
        uint256 finalPrice
    ) external;

    function onFeedRequested(
        uint256 orderId,
        FeedType feedType
    ) external;
}

contracts/libraries/NSTTypes.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title NSTTypes
 * @notice 数据类型定义 - NST Options MVP
 * @dev 定义所有合约共用的数据结构和枚举
 */

/**
 * @notice 订单方向
 */
enum Direction {
    Call,   // 看涨
    Put     // 看跌
}

/**
 * @notice 卖方类型
 */
enum SellerType {
    FreeSeller,         // 自由卖方
    SeatSeller,         // 席位卖方
    DesignatedSeller    // 指定卖方
}

/**
 * @notice 强平规则
 */
enum LiquidationRule {
    NoLiquidation,          // 无强平，到期结算
    ConsecutiveLimitUp,     // 连续涨停板强平（触板/封板）
    ConsecutiveDailyGain    // 连续单日涨幅≥X%强平
}

/**
 * @notice 订单状态
 */
enum OrderStatus {
    RFQ_CREATED,            // 询价已创建
    QUOTING,                // 报价中
    MATCHED,                // 已匹配，待喂价
    WAITING_INITIAL_FEED,   // 待期初喂价
    LIVE,                   // 持仓中
    WAITING_FINAL_FEED,     // 待期末喂价
    PENDING_SETTLEMENT,     // 待结算
    ARBITRATION,            // 仲裁中
    SETTLED,                // 已结算
    LIQUIDATED,             // 已强平
    CANCELLED               // 已取消
}

/**
 * @notice 报价状态
 */
enum QuoteStatus {
    Active,     // 有效
    Accepted,   // 已接受
    Rejected,   // 已拒绝
    Expired     // 已过期
}

/**
 * @notice 喂价类型
 */
enum FeedType {
    Initial,        // 期初喂价
    Dynamic,        // 动态保证金调整喂价
    Final,          // 期末喂价
    Arbitration     // 仲裁喂价
}

/**
 * @notice 喂价档位
 */
enum FeedTier {
    Tier_5_3,   // 5个喂价员，取3个有效
    Tier_7_5,   // 7个喂价员，取5个有效
    Tier_10_7   // 10个喂价员，取7个有效
}

/**
 * @notice 喂价规则
 */
enum FeedRule {
    NormalFeed,         // 正常喂价（市价）
    VolumeBasedFeed     // 跟量成交喂价（需真实成交量支持）
}

/**
 * @notice 订单结构体
 */
struct Order {
    // 基础信息
    uint256 orderId;
    address buyer;
    address seller;
    
    // 标的信息
    string underlyingName;      // 标的名称
    string underlyingCode;      // 标的代码
    string market;              // 市场
    string country;             // 国家
    string refPrice;            // 参考价格
    
    // 合约要素
    Direction direction;        // 看涨/看跌
    uint256 notionalUSDT;       // 名义本金
    uint256 strikePrice;        // 行权价
    uint256 expiryTimestamp;    // 到期时间
    
    // 费率与保证金
    uint256 premiumRate;        // 期权费率（基点）
    uint256 premiumAmount;      // 期权费金额
    uint256 initialMargin;      // 初始保证金
    uint256 currentMargin;      // 当前保证金
    uint256 minMarginRate;      // 最低保证金率（基点）
    uint256 maxPremiumRate;     // 最高期权费率限制（基点，0=不限）
    
    // 平仓规则
    LiquidationRule liquidationRule;
    uint8 consecutiveDays;      // 连续天数
    uint8 dailyLimitPercent;    // 单日涨幅阈值
    uint8 exerciseDelay;        // T+X 行权延迟
    
    // 卖方类型
    SellerType sellerType;
    address designatedSeller;   // 指定卖方地址
    
    // 仲裁与追保配置
    uint256 arbitrationWindow;  // 仲裁窗口
    uint256 marginCallDeadline; // 追保截止时间
    
    // 分红调整
    bool dividendAdjustment;    // 是否调整行权价
    
    // 喂价规则
    FeedRule feedRule;          // 正常喂价/跟量成交喂价
    
    // 状态与时间
    OrderStatus status;
    uint256 createdAt;
    uint256 matchedAt;
    uint256 settledAt;
    uint256 lastFeedPrice;      // 最后一次喂价价格
    uint256 dividendAmount;     // 累计分红金额 (用于调整行权价)
}

/**
 * @notice 报价结构体
 */
struct Quote {
    uint256 quoteId;
    uint256 orderId;
    address seller;
    SellerType sellerType;
    
    uint256 premiumRate;        // 报价费率（基点）
    uint256 premiumAmount;      // 期权费金额
    uint256 marginRate;         // 保证金比例
    uint256 marginAmount;       // 保证金金额
    
    LiquidationRule liquidationRule;
    uint8 consecutiveDays;
    uint8 dailyLimitPercent;
    
    uint256 createdAt;
    uint256 expiresAt;          // 报价有效期
    QuoteStatus status;
}

/**
 * @notice 席位信息结构体
 */
struct Seat {
    address owner;
    uint256 depositAmount;      // 席位押金
    uint256 nstStaked;          // 质押的NST数量
    uint256 stakeStartTime;     // 质押开始时间
    uint256 currentExposure;    // 当前风险敞口
    uint256 maxExposure;        // 最大允许敞口
    bool isActive;
}

/**
 * @notice 喂价请求结构体
 */
struct FeedRequest {
    uint256 requestId;
    uint256 orderId;
    FeedType feedType;
    FeedTier tier;
    uint256 deadline;           // 喂价截止时间
    uint256 createdAt;
    uint256 totalFeeders;       // 需要的喂价员数量
    uint256 submittedCount;     // 已提交数量
    uint256 finalPrice;         // 最终价格
    bool finalized;             // 是否已完成
}

/**
 * @notice 用户积分结构体
 */
struct UserPoints {
    uint256 totalPoints;        // 累计积分
    uint256 claimedPoints;      // 已领取空投的积分
    uint256 availablePoints;    // 可用积分
    uint256 lastUpdateTime;     // 最后更新时间
}

contracts/vault/VaultManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../core/Config.sol";

/**
 * @title VaultManager
 * @notice 资金池管理合约 - 资金调度与状态执行中枢
 * @dev 只接受授权的合约调用，不直接与用户交互
 */
contract VaultManager is AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 角色定义 ====================
    bytes32 public constant VAULT_OPERATOR_ROLE = keccak256("VAULT_OPERATOR_ROLE");

    // ==================== 状态变量 ====================
    Config public config;
    
    // 资金池余额
    mapping(address => uint256) public marginPoolBalance;       // 保证金池
    mapping(address => uint256) public profitPoolBalance;       // 生态利润池
    mapping(address => uint256) public lpPoolBalance;           // 代币LP池
    mapping(address => uint256) public interactPoolBalance;     // 合约交互池
    mapping(address => uint256) public donationPoolBalance;     // 捐赠节点池

    // 用户保证金余额
    mapping(address => mapping(address => uint256)) public userMarginBalance;  // user => token => balance

    // ==================== 事件 ====================
    event MarginDeposited(
        address indexed user,
        address indexed token,
        uint256 amount,
        uint256 timestamp
    );

    event MarginWithdrawn(
        address indexed user,
        address indexed token,
        uint256 amount,
        uint256 timestamp
    );

    event MarginTransferred(
        address indexed from,
        address indexed to,
        address indexed token,
        uint256 amount,
        string reason,
        uint256 timestamp
    );

    event FeeCollected(
        address indexed token,
        uint256 amount,
        string feeType,
        uint256 timestamp
    );

    event ProfitDistributed(
        address indexed token,
        uint256 amount,
        string poolType,
        uint256 timestamp
    );

    // ==================== 构造函数 ====================
    constructor(address _config, address _admin) {
        config = Config(_config);
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(VAULT_OPERATOR_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier onlyOperator() {
        require(hasRole(VAULT_OPERATOR_ROLE, msg.sender), "VaultManager: caller is not operator");
        _;
    }

    // ==================== 保证金操作 ====================

    /**
     * @notice 存入保证金
     * @param _user 用户地址
     * @param _token 代币地址
     * @param _amount 金额
     */
    function depositMargin(
        address _user,
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        
        IERC20(_token).safeTransferFrom(_user, address(this), _amount);
        userMarginBalance[_user][_token] += _amount;
        marginPoolBalance[_token] += _amount;

        emit MarginDeposited(_user, _token, _amount, block.timestamp);
    }

    /**
     * @notice 提取保证金
     * @param _user 用户地址
     * @param _token 代币地址
     * @param _amount 金额
     */
    function withdrawMargin(
        address _user,
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        require(userMarginBalance[_user][_token] >= _amount, "VaultManager: insufficient balance");

        userMarginBalance[_user][_token] -= _amount;
        marginPoolBalance[_token] -= _amount;
        IERC20(_token).safeTransfer(_user, _amount);

        emit MarginWithdrawn(_user, _token, _amount, block.timestamp);
    }

    /**
     * @notice 内部转移保证金（订单结算时使用）
     * @param _from 发送方
     * @param _to 接收方
     * @param _token 代币地址
     * @param _amount 金额
     * @param _reason 转移原因
     */
    function transferMargin(
        address _from,
        address _to,
        address _token,
        uint256 _amount,
        string calldata _reason
    ) external onlyOperator nonReentrant whenNotPaused {
        require(userMarginBalance[_from][_token] >= _amount, "VaultManager: insufficient balance");

        userMarginBalance[_from][_token] -= _amount;
        userMarginBalance[_to][_token] += _amount;

        emit MarginTransferred(_from, _to, _token, _amount, _reason, block.timestamp);
    }

    // ==================== 手续费操作 ====================

    /**
     * @notice 收取手续费
     * @param _user 用户地址
     * @param _token 代币地址
     * @param _amount 金额
     * @param _feeType 费用类型
     */
    function collectFee(
        address _user,
        address _token,
        uint256 _amount,
        string calldata _feeType
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");

        IERC20(_token).safeTransferFrom(_user, address(this), _amount);
        profitPoolBalance[_token] += _amount;

        emit FeeCollected(_token, _amount, _feeType, block.timestamp);
    }

    // ==================== 退款操作 (§15.2) ====================

    /**
     * @notice 退还期权费给买方
     * @param _buyer 买方地址
     * @param _amount 期权费金额
     * @dev 用于初始喂价超时等场景
     */
    function refundPremium(
        address _buyer,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_buyer != address(0), "VaultManager: invalid buyer address");
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        
        address token = config.usdtAddress();
        require(IERC20(token).balanceOf(address(this)) >= _amount, "VaultManager: insufficient balance");
        
        IERC20(token).safeTransfer(_buyer, _amount);
        
        emit MarginTransferred(address(this), _buyer, token, _amount, "premium_refund", block.timestamp);
    }

    /**
     * @notice 退还保证金给卖方
     * @param _seller 卖方地址
     * @param _amount 保证金金额
     * @dev 用于超时取消等场景
     */
    function refundMargin(
        address _seller,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_seller != address(0), "VaultManager: invalid seller address");
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        
        address token = config.usdtAddress();
        require(marginPoolBalance[token] >= _amount, "VaultManager: insufficient margin pool");
        
        marginPoolBalance[token] -= _amount;
        IERC20(token).safeTransfer(_seller, _amount);
        
        emit MarginTransferred(address(this), _seller, token, _amount, "margin_refund", block.timestamp);
    }

    /**
     * @notice 将违约金转入国库（利润池）
     * @param _amount 违约金金额
     * @dev 用于卖方违约场景
     */
    function transferToTreasury(
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        
        address token = config.usdtAddress();
        require(marginPoolBalance[token] >= _amount, "VaultManager: insufficient margin pool");
        
        marginPoolBalance[token] -= _amount;
        profitPoolBalance[token] += _amount;
        
        emit ProfitDistributed(token, _amount, "penalty_to_treasury", block.timestamp);
    }

    /**
     * @notice 从用户保证金余额中扣除违约金到利润池
     * @param _user 被扣款用户
     * @param _token 代币地址
     * @param _amount 违约金金额
     * @dev 用于超时取消等违约场景，从用户余额扣减并转入利润池
     */
    function penaltyToTreasury(
        address _user,
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        require(userMarginBalance[_user][_token] >= _amount, "VaultManager: insufficient user balance");

        userMarginBalance[_user][_token] -= _amount;
        marginPoolBalance[_token] -= _amount;
        profitPoolBalance[_token] += _amount;

        emit FeeCollected(_token, _amount, "penalty", block.timestamp);
    }

    /**
     * @notice 分配利润到各池子
     * @param _token 代币地址
     * @param _amount 总金额
     */
    function distributeProfits(
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(profitPoolBalance[_token] >= _amount, "VaultManager: insufficient profit pool");

        profitPoolBalance[_token] -= _amount;

        // 按比例分配
        uint256 nodeReward = (_amount * config.nodeRewardShare()) / 10000;
        uint256 buyback = (_amount * config.tokenBuybackShare()) / 10000;
        uint256 lp = (_amount * config.lpPoolShare()) / 10000;
        // 剩余部分分配给团队、基金会、DAO、成长节点
        // 这里简化处理，实际需要转账到对应地址

        lpPoolBalance[_token] += lp;
        donationPoolBalance[_token] += nodeReward;

        emit ProfitDistributed(_token, _amount, "all", block.timestamp);
    }

    /**
     * @notice 转移喂价费用到喂价生态
     * @param _token 代币地址
     * @param _amount 金额
     * @param _feedProtocol 喂价协议地址
     */
    function transferToFeedProtocol(
        address _token,
        uint256 _amount,
        address _feedProtocol
    ) external onlyOperator nonReentrant whenNotPaused {
        require(interactPoolBalance[_token] >= _amount, "VaultManager: insufficient interact pool");
        interactPoolBalance[_token] -= _amount;
        IERC20(_token).safeTransfer(_feedProtocol, _amount);
    }

    // ==================== LP池操作 ====================

    /**
     * @notice 存入LP池
     */
    function depositToLPPool(
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        IERC20(_token).safeTransferFrom(msg.sender, address(this), _amount);
        lpPoolBalance[_token] += _amount;
        
        emit ProfitDistributed(_token, _amount, "lp_deposit", block.timestamp);
    }

    /**
     * @notice 从LP池提取
     */
    function withdrawFromLPPool(
        address _token,
        uint256 _amount,
        address _recipient
    ) external onlyOperator nonReentrant whenNotPaused {
        require(lpPoolBalance[_token] >= _amount, "VaultManager: insufficient LP pool");
        lpPoolBalance[_token] -= _amount;
        IERC20(_token).safeTransfer(_recipient, _amount);
        
        emit ProfitDistributed(_token, _amount, "lp_withdraw", block.timestamp);
    }

    // ==================== 交互池操作 ====================

    /**
     * @notice 存入交互池（用于支付合约交互费用）
     */
    function depositToInteractPool(
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        IERC20(_token).safeTransferFrom(msg.sender, address(this), _amount);
        interactPoolBalance[_token] += _amount;
        
        emit ProfitDistributed(_token, _amount, "interact_deposit", block.timestamp);
    }

    /**
     * @notice 从交互池提取
     */
    function withdrawFromInteractPool(
        address _token,
        uint256 _amount,
        address _recipient
    ) external onlyOperator nonReentrant whenNotPaused {
        require(interactPoolBalance[_token] >= _amount, "VaultManager: insufficient interact pool");
        interactPoolBalance[_token] -= _amount;
        IERC20(_token).safeTransfer(_recipient, _amount);
        
        emit ProfitDistributed(_token, _amount, "interact_withdraw", block.timestamp);
    }

    // ==================== 捐赠节点池操作 ====================

    /**
     * @notice 存入捐赠节点池
     */
    function depositToDonationPool(
        address _token,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        IERC20(_token).safeTransferFrom(msg.sender, address(this), _amount);
        donationPoolBalance[_token] += _amount;
        
        emit ProfitDistributed(_token, _amount, "donation_deposit", block.timestamp);
    }

    /**
     * @notice 从捐赠节点池提取（用于节点奖励分配）
     */
    function withdrawFromDonationPool(
        address _token,
        uint256 _amount,
        address _recipient
    ) external onlyOperator nonReentrant whenNotPaused {
        require(donationPoolBalance[_token] >= _amount, "VaultManager: insufficient donation pool");
        donationPoolBalance[_token] -= _amount;
        IERC20(_token).safeTransfer(_recipient, _amount);
        
        emit ProfitDistributed(_token, _amount, "donation_withdraw", block.timestamp);
    }

    /**
     * @notice 批量分配节点奖励
     * @param _token 代币地址
     * @param _recipients 接收者列表
     * @param _amounts 金额列表
     */
    function batchDistributeNodeRewards(
        address _token,
        address[] calldata _recipients,
        uint256[] calldata _amounts
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_recipients.length == _amounts.length, "VaultManager: length mismatch");
        
        uint256 totalAmount = 0;
        for (uint256 i = 0; i < _amounts.length; i++) {
            totalAmount += _amounts[i];
        }
        require(donationPoolBalance[_token] >= totalAmount, "VaultManager: insufficient donation pool");
        
        donationPoolBalance[_token] -= totalAmount;
        
        for (uint256 i = 0; i < _recipients.length; i++) {
            IERC20(_token).safeTransfer(_recipients[i], _amounts[i]);
        }
        
        emit ProfitDistributed(_token, totalAmount, "node_rewards_batch", block.timestamp);
    }

    // ==================== 利润池高级操作 ====================

    /**
     * @notice 从利润池转入其他子池
     * @param _token 代币地址
     * @param _lpAmount LP池金额
     * @param _interactAmount 交互池金额
     * @param _donationAmount 捐赠池金额
     */
    function allocateProfitToSubPools(
        address _token,
        uint256 _lpAmount,
        uint256 _interactAmount,
        uint256 _donationAmount
    ) external onlyOperator nonReentrant whenNotPaused {
        uint256 totalAmount = _lpAmount + _interactAmount + _donationAmount;
        require(profitPoolBalance[_token] >= totalAmount, "VaultManager: insufficient profit pool");
        
        profitPoolBalance[_token] -= totalAmount;
        lpPoolBalance[_token] += _lpAmount;
        interactPoolBalance[_token] += _interactAmount;
        donationPoolBalance[_token] += _donationAmount;
        
        emit ProfitDistributed(_token, totalAmount, "profit_allocation", block.timestamp);
    }

    // ==================== 仲裁奖励操作 ====================

    /**
     * @notice 发放仲裁奖励 (§15.4)
     * @param _recipient 奖励接收者
     * @param _amount 奖励金额
     * @dev 从利润池中发放仲裁奖励给成功的仲裁发起方
     */
    function transferReward(
        address _recipient,
        uint256 _amount
    ) external onlyOperator nonReentrant whenNotPaused {
        require(_recipient != address(0), "VaultManager: invalid recipient");
        require(_amount > 0, "VaultManager: amount must be greater than 0");
        
        // 从利润池扣除奖励金额
        address usdtAddress = address(config.optionsCoreAddress()) != address(0) 
            ? address(0x9f2140319726F9b851073a303415f13EC0cdA269) // BSC Testnet USDT
            : address(0x55d398326f99059fF775485246999027B3197955); // BSC Mainnet USDT
            
        require(profitPoolBalance[usdtAddress] >= _amount, "VaultManager: insufficient profit pool for reward");
        
        profitPoolBalance[usdtAddress] -= _amount;
        IERC20(usdtAddress).safeTransfer(_recipient, _amount);
        
        emit ProfitDistributed(usdtAddress, _amount, "arbitration_reward", block.timestamp);
    }

    // ==================== 查询函数 ====================

    /**
     * @notice 查询用户保证金余额
     */
    function getUserMarginBalance(
        address _user,
        address _token
    ) external view returns (uint256) {
        return userMarginBalance[_user][_token];
    }

    /**
     * @notice 查询总保证金池余额
     */
    function getTotalMarginPool(address _token) external view returns (uint256) {
        return marginPoolBalance[_token];
    }

    /**
     * @notice 查询利润池余额
     */
    function getProfitPoolBalance(address _token) external view returns (uint256) {
        return profitPoolBalance[_token];
    }

    // ==================== 管理函数 ====================

    /**
     * @notice 更新 Config 地址
     */
    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    /**
     * @notice 授权操作者角色
     */
    function grantOperatorRole(address _operator) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(VAULT_OPERATOR_ROLE, _operator);
    }

    /**
     * @notice 暂停合约
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @notice 恢复合约
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    /**
     * @notice 管理员直接设置用户保证金余额（用于迁移/测试场景）
     * @dev 仅限 DEFAULT_ADMIN_ROLE，需要合约中有足够的 token 余额
     * @param _user 用户地址
     * @param _token 代币地址
     * @param _amount 设置的余额金额
     */
    function adminSetMarginBalance(
        address _user,
        address _token,
        uint256 _amount
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        uint256 currentBalance = userMarginBalance[_user][_token];
        
        if (_amount > currentBalance) {
            // 增加余额
            uint256 diff = _amount - currentBalance;
            marginPoolBalance[_token] += diff;
        } else if (_amount < currentBalance) {
            // 减少余额
            uint256 diff = currentBalance - _amount;
            marginPoolBalance[_token] -= diff;
        }
        
        userMarginBalance[_user][_token] = _amount;
        
        emit MarginDeposited(_user, _token, _amount, block.timestamp);
    }
}

